/**
 * Platform-aware sync storage abstraction.
 *
 * Web: thin pass-through to window.localStorage.
 * Native: in-memory cache hydrated from @capacitor/preferences at boot,
 * with fire-and-forget write-through and pause-driven flush.
 *
 * Consumers see a sync API ({@link getItem}, {@link setItem}, {@link removeItem},
 * {@link keys}, {@link clear}). Bootstrap awaits {@link whenReady} before mounting
 * React so module-load reads see the hydrated cache.
 */

import { Capacitor } from '@capacitor/core';
import { Preferences } from '@capacitor/preferences';

export const META_KEYS = Object.freeze({
  MIGRATION_V1: 'sport-wizard-meta:storage-migration-v1-completed',
});

const META_KEYS_TO_PRESERVE = [META_KEYS.MIGRATION_V1];

const STORAGE_PROBE_KEY = '__storage_test__';

export function createWebBackend({ localStorage } = {}) {
  // Read store lazily so tests that reassign window.localStorage between tests
  // (Object.defineProperty(window, 'localStorage', ...)) see the updated mock.
  const fixedStore = localStorage ?? null;
  function getStore() {
    if (fixedStore) return fixedStore;
    if (typeof window === 'undefined' || !window.localStorage) return null;
    return window.localStorage;
  }

  function probe() {
    // Re-probe on each call rather than memoise. Memoising broke
    // persistenceManager.test.js, which mutates setItem to throw
    // mid-test (same store reference, different implementation) and
    // expects isSupported to flip to false. The probe writes a
    // ~1-byte key + immediate remove — cheap on real localStorage.
    // If a future profiler shows it on a hot path, push memoisation
    // up to the cacheUtils call sites so the test's reference-based
    // mutation pattern still works.
    const store = getStore();
    if (!store) return false;
    try {
      store.setItem(STORAGE_PROBE_KEY, 'test');
      store.removeItem(STORAGE_PROBE_KEY);
      return true;
    } catch {
      return false;
    }
  }

  const readyPromise = Promise.resolve();

  return {
    get isSupported() { return probe(); },
    get length() { const s = getStore(); return s ? s.length : 0; },
    getItem(key) { const s = getStore(); return s ? s.getItem(key) : null; },
    setItem(key, value) { const s = getStore(); if (s) s.setItem(key, value); },
    setItemAwaitable(key, value) {
      const s = getStore();
      if (s) s.setItem(key, value);
      return Promise.resolve();
    },
    removeItem(key) { const s = getStore(); if (s) s.removeItem(key); },
    removeItemAwaitable(key) {
      const s = getStore();
      if (s) s.removeItem(key);
      return Promise.resolve();
    },
    clear() { const s = getStore(); if (s) s.clear(); },
    keys() {
      const s = getStore();
      if (!s) return [];
      const out = [];
      for (let i = 0; i < s.length; i++) {
        const k = s.key(i);
        if (k != null) out.push(k);
      }
      return out;
    },
    key(index) {
      const s = getStore();
      if (!s) return null;
      return typeof s.key === 'function' ? s.key(index) : null;
    },
    whenReady() { return readyPromise; },
    isReady() { return true; },
    flush() { return Promise.resolve(); },
  };
}

export function createNativeBackend({ preferences = Preferences, localStorage } = {}) {
  const cache = new Map();
  const inFlight = new Set();
  let ready = false;

  function track(promise) {
    inFlight.add(promise);
    promise.finally(() => { inFlight.delete(promise); });
    return promise;
  }

  async function hydrate() {
    let prefKeys = [];
    try {
      const result = await preferences.keys();
      prefKeys = result?.keys ?? [];
    } catch {
      prefKeys = [];
    }

    await Promise.all(prefKeys.map(async (key) => {
      try {
        const result = await preferences.get({ key });
        if (result && result.value != null) {
          cache.set(key, String(result.value));
        }
      } catch {
        /* swallow per-key read errors */
      }
    }));

    if (!cache.has(META_KEYS.MIGRATION_V1)) {
      await runLegacyMigration();
    }
  }

  async function runLegacyMigration() {
    const legacy = localStorage ?? (typeof window !== 'undefined' ? window.localStorage : null);
    const writes = [];

    if (legacy) {
      try {
        for (let i = 0; i < legacy.length; i++) {
          const key = legacy.key(i);
          if (!key) continue;
          if (key === STORAGE_PROBE_KEY) continue;
          if (key === META_KEYS.MIGRATION_V1) continue;
          if (cache.has(key)) continue;
          let value = null;
          try {
            value = legacy.getItem(key);
          } catch {
            continue;
          }
          if (value == null) continue;
          cache.set(key, String(value));
          writes.push(preferences.set({ key, value: String(value) }));
        }
      } catch {
        /* ignore localStorage iteration failures — fresh install or eviction */
      }
    }

    await Promise.allSettled(writes);
    cache.set(META_KEYS.MIGRATION_V1, '1');
    await preferences.set({ key: META_KEYS.MIGRATION_V1, value: '1' });
  }

  const readyPromise = (async () => {
    try {
      await hydrate();
    } finally {
      ready = true;
    }
  })();

  // Distinct sentinel so "ready" is unambiguous. Returning `null` from ensureReady
  // collided with `getItem`'s legitimate `null` fallback, leaving its guard inert.
  const READY = Symbol('storageBackend.ready');

  function ensureReady(returnIfNot) {
    if (ready) return READY;
    if (process.env.NODE_ENV === 'production') return returnIfNot;
    throw new Error(
      'storageBackend used before whenReady() resolved — ensure bootstrap awaits storageBackend.whenReady() before mounting.'
    );
  }

  // Default flush timeout: fits inside Android's ~5s pause budget while leaving
  // headroom for the pause handler itself.
  const DEFAULT_FLUSH_TIMEOUT_MS = 4000;

  return {
    isSupported: true,
    get length() {
      if (ensureReady(0) !== READY) return 0;
      return cache.size;
    },
    getItem(key) {
      if (ensureReady(null) !== READY) return null;
      return cache.has(key) ? cache.get(key) : null;
    },
    setItem(key, value) {
      if (ensureReady(undefined) !== READY) return;
      const stringValue = String(value);
      cache.set(key, stringValue);
      track(preferences.set({ key, value: stringValue }).catch((err) => {
        console.warn('storageBackend: Preferences.set failed', { key, err });
      }));
    },
    setItemAwaitable(key, value) {
      if (ensureReady(undefined) !== READY) return Promise.resolve();
      const stringValue = String(value);
      cache.set(key, stringValue);
      const p = preferences.set({ key, value: stringValue });
      // Asymmetry on purpose: track a swallowing wrapper so flush() never
      // hangs on a rejected write, but return the raw promise so callers
      // (Supabase auth) can observe write failures and react.
      track(p.catch(() => {}));
      return p.then(() => undefined);
    },
    removeItem(key) {
      if (ensureReady(undefined) !== READY) return;
      cache.delete(key);
      track(preferences.remove({ key }).catch((err) => {
        console.warn('storageBackend: Preferences.remove failed', { key, err });
      }));
    },
    removeItemAwaitable(key) {
      if (ensureReady(undefined) !== READY) return Promise.resolve();
      cache.delete(key);
      const p = preferences.remove({ key });
      // Same asymmetry as setItemAwaitable: swallowing wrapper for flush(),
      // raw promise returned so the caller can observe failure.
      track(p.catch(() => {}));
      return p.then(() => undefined);
    },
    clear() {
      if (ensureReady(undefined) !== READY) return;
      // Known race: between the synchronous cache.clear() below and the
      // awaited preferences.clear() inside `reseed`, an OS kill would leave
      // Preferences holding the old data and the next boot's hydrate() would
      // resurrect it. This is the same fire-and-forget durability tradeoff
      // we accept for setItem/removeItem; callers that need synchronous
      // wipe-on-disk semantics should await preferences.clear() themselves.
      const preserved = {};
      for (const k of META_KEYS_TO_PRESERVE) {
        if (cache.has(k)) preserved[k] = cache.get(k);
      }
      cache.clear();
      for (const [k, v] of Object.entries(preserved)) cache.set(k, v);

      const reseed = (async () => {
        try {
          await preferences.clear();
        } catch (err) {
          console.warn('storageBackend: Preferences.clear failed', err);
        }
        for (const [k, v] of Object.entries(preserved)) {
          try {
            await preferences.set({ key: k, value: v });
          } catch (err) {
            console.warn('storageBackend: re-seed of preserved key failed', { key: k, err });
          }
        }
      })();
      track(reseed);
    },
    keys() {
      if (ensureReady([]) !== READY) return [];
      return Array.from(cache.keys());
    },
    key(index) {
      // O(n) per call (Map → array). All in-tree callers iterate via keys()
      // (snapshot once); this exists for Storage-API compatibility — don't
      // call it inside a hot loop.
      if (ensureReady(null) !== READY) return null;
      return Array.from(cache.keys())[index] ?? null;
    },
    whenReady() { return readyPromise; },
    isReady() { return ready; },
    async flush(timeoutMs = DEFAULT_FLUSH_TIMEOUT_MS) {
      // Timeout guard: a hung Preferences.set (plugin bug, OS suspension) must
      // never deadlock the pause handler.
      //
      // The while-loop drains writes that arrive *during* a previous batch's
      // settling. The only intended caller (App pause handler) sees no new
      // writes after pause fires, so loop re-entry isn't expected — but if a
      // future caller invokes flush concurrent with active writes, the timeout
      // bound below still caps the total wait.
      const deadline = Date.now() + timeoutMs;
      while (inFlight.size > 0) {
        const remaining = deadline - Date.now();
        if (remaining <= 0) {
          console.warn('storageBackend.flush: timeout exceeded with', inFlight.size, 'writes still in flight');
          return;
        }
        let timer;
        const timeoutPromise = new Promise((resolve) => {
          timer = setTimeout(resolve, remaining);
        });
        try {
          await Promise.race([
            Promise.allSettled(Array.from(inFlight)),
            timeoutPromise,
          ]);
        } finally {
          clearTimeout(timer);
        }
      }
    },
  };
}

export const storageBackend = Capacitor.isNativePlatform()
  ? createNativeBackend()
  : createWebBackend();

export default storageBackend;
