import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css'; // Or your main CSS file
import { storageBackend } from './utils/storageBackend';
import * as serviceWorkerRegistration from './serviceWorkerRegistration';

// Wait for the storage backend to hydrate before mounting React. On web this
// resolves on the next microtask (no user-visible delay). On native, this is
// the Preferences.keys() + parallel get() pass that ensures App.js's top-level
// reads (migrateStorageKeys, dismissedModalsPersistence factory, etc.) see the
// fully-hydrated cache. App is dynamically imported below for the same reason.
function renderBootstrapFailure(error) {
  const root = document.getElementById('root');
  if (!root) return;
  // Minimal inline fallback so the user sees something other than a blank screen
  // when the bundle fails to load (network blip on slow native, parse error, etc.).
  // Built with DOM APIs rather than innerHTML so message text cannot be interpreted
  // as markup, even if the error originates from untrusted input.
  while (root.firstChild) root.removeChild(root.firstChild);
  const wrap = document.createElement('div');
  wrap.style.cssText = 'min-height:100vh;display:flex;align-items:center;justify-content:center;padding:24px;background:#0f172a;color:#e2e8f0;font-family:system-ui,-apple-system,sans-serif;text-align:center;';
  const inner = document.createElement('div');
  inner.style.maxWidth = '480px';
  const heading = document.createElement('h1');
  heading.style.cssText = 'font-size:18px;margin:0 0 12px;color:#7dd3fc;';
  heading.textContent = "Sport Wizard couldn't start";
  const para = document.createElement('p');
  para.style.cssText = 'margin:0 0 16px;font-size:14px;line-height:1.5;color:#cbd5e1;';
  para.textContent = 'Something went wrong while loading the app. Please reopen it; if this keeps happening, check your connection or reinstall.';
  const detail = document.createElement('p');
  detail.style.cssText = 'margin:0;font-size:12px;color:#64748b;font-family:ui-monospace,monospace;';
  detail.textContent = (error && (error.message || String(error))) || 'unknown error';
  inner.append(heading, para, detail);
  wrap.append(inner);
  root.append(wrap);
}

async function bootstrap() {
  await storageBackend.whenReady();
  const { default: App } = await import('./App');

  const root = ReactDOM.createRoot(document.getElementById('root'));
  root.render(
    // Temporarily disabled React.StrictMode to fix refresh token issues
    // React.StrictMode causes double-mounting which triggers Supabase security detection
    // <React.StrictMode>
    <App />
    // </React.StrictMode>
  );

  serviceWorkerRegistration.register();
}

bootstrap().catch((error) => {
  // eslint-disable-next-line no-console
  console.error('Bootstrap failed:', error);
  renderBootstrapFailure(error);
});
